/**
 * Idempotent NEA agencies seeding.
 *
 * 2026-06 (Tony's bulk update): seeds/updates the verified NEA (National
 * Employment Authority) agencies into the nea_agencies table from the
 * authoritative NEA portal export. Runs on every server boot — re-runs
 * are no-ops because we ON CONFLICT (license_number) DO UPDATE.
 *
 * What this guarantees:
 *   • Every agency in this list exists in the DB with the correct
 *     expiryDate, statusOverride="verified", and isPublished=true
 *   • If an admin manually edits an agency between deploys, our update
 *     here will OVERWRITE the agencyName / serviceType / email / expiry —
 *     this is intentional so the NEA portal stays the source of truth
 *   • Agencies removed from the NEA portal are NOT auto-removed here
 *     (we don't want to nuke ones admins are still investigating)
 *
 * Total: 581 agencies, parsed from Tony's NEA portal paste.
 *
 * Source: NEA portal export pasted by Tony on 2026-06-26.
 * Issue dates are best-guess (expiry minus 1 year) because the NEA portal
 * doesn't expose them on the public list — this is fine because the
 * issueDate column is informational only; expiry drives the licence-valid
 * gating logic.
 */
import { pool } from "../db";

interface NeaSeed {
  agencyName: string;
  licenseNumber: string;
  email: string | null;
  serviceType: string | null;
  issueDate: string;   // YYYY-MM-DD
  expiryDate: string;  // YYYY-MM-DD
}

