export async function ensureNeaAgenciesSeeded(): Promise<void> {
  const client = await pool.connect();
  let inserted = 0;
  let updated = 0;
  let errors = 0;
  try {
    for (const a of NEA_AGENCIES) {
      try {
        // ON CONFLICT (license_number) DO UPDATE — idempotent upsert.
        // We refresh agencyName, email, serviceType, expiryDate, and
        // statusOverride on every run so NEA portal changes propagate.
        // isPublished stays true unless an admin explicitly hides it.
        const result = await client.query<{ inserted: boolean }>(
          `INSERT INTO nea_agencies
             (agency_name, license_number, email, service_type, issue_date,
              expiry_date, status_override, is_published, last_updated)
           VALUES ($1, $2, $3, $4, $5::date, $6::date, 'verified', true, NOW())
           ON CONFLICT (license_number) DO UPDATE
             SET agency_name = EXCLUDED.agency_name,
                 email = EXCLUDED.email,
                 service_type = EXCLUDED.service_type,
                 expiry_date = EXCLUDED.expiry_date,
                 status_override = 'verified',
                 last_updated = NOW()
           RETURNING (xmax = 0) AS inserted`,
          [a.agencyName, a.licenseNumber, a.email, a.serviceType, a.issueDate, a.expiryDate],
        );
        if (result.rows[0]?.inserted) inserted++;
        else updated++;
      } catch (rowErr: any) {
        errors++;
        console.warn(
          `[ensureNeaAgencies] failed to upsert ${a.licenseNumber} (${a.agencyName}): ${rowErr?.message}`,
        );
      }
    }
    console.log(
      `[ensureNeaAgencies] ✓ Done: ${inserted} inserted, ${updated} updated, ${errors} errors ` +
      `out of ${NEA_AGENCIES.length} agencies in source.`,
    );
  } catch (err: any) {
    console.error("[ensureNeaAgencies] FAILED:", err?.message);
  } finally {
    client.release();
  }
}
